import sys
from collections import deque
from typing import List

class Node:
    def __init__(self, data: int):
        self.data = data
        self.left = None
        self.right = None

class Solution:
    def topView(self, root: Node) -> List[int]:
        if not root:
            return []

        q = deque([(root, 0)])
        top_nodes = {}
        min_hd = 0
        max_hd = 0

        while q:
            node, hd = q.popleft()
            if hd not in top_nodes:
                top_nodes[hd] = node.data
                min_hd = min(min_hd, hd)
                max_hd = max(max_hd, hd)

            if node.left:
                q.append((node.left, hd - 1))
            if node.right:
                q.append((node.right, hd + 1))

        result = [top_nodes[hd] for hd in range(min_hd, max_hd + 1)]
        return result

if __name__ == '__main__':
    n = int(sys.stdin.readline().strip())
    pre_order = list(map(int, sys.stdin.readline().strip().split()))
    hd = list(map(int, sys.stdin.readline().strip().split()))

    nodes = {i: Node(pre_order[i]) for i in range(n)}
    for i in range(n):
