#include <numeric>
#include <iostream>
#include <queue>
#include <unordered_map>
#include <vector>

using namespace std;

struct Node {
    int data;
    Node* left;
    Node* right;
    Node(int val) : data(val), left(nullptr), right(nullptr) {}
};

class Solution {
public:
    vector<int> topView(Node* root) {
        if (!root) return {};

        queue<pair<Node*, int>> q;
        q.push({root, 0});
        unordered_map<int, int> top_nodes;
        int min_hd = 0, max_hd = 0;

        while (!q.empty()) {
            auto _tmp_binding_0 = q.front(); auto node = _tmp_binding_0.first; auto hd = _tmp_binding_0.second; q.pop();
            if (top_nodes.find(hd) == top_nodes.end()) {
                top_nodes[hd] = node->data;
                min_hd = min(min_hd, hd);
                max_hd = max(max_hd, hd);
            }

            if (node->left) q.push({node->left, hd - 1});
            if (node->right) q.push({node->right, hd + 1});
        }

        vector<int> result;
        for (int hd = min_hd; hd <= max_hd; ++hd) {
            result.push_back(top_nodes[hd]);
        }
        return result;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int n;
    cin >> n;
    vector<int> pre_order(n);
    for (int& val : pre_order) cin >> val;
    vector<int> hd(n);
    for (int& h : hd) cin >> h;

    unordered_map<int, Node*> nodes;
    for (int i = 0; i < n; ++i) {
        nodes[i] = new Node(pre_order[i]);
    }
    for (int i = 0; i < n; ++i) {
        if (2 * i + 1 < n) {
            nodes[i]->left = nodes[2 * i + 1];
        }
        if (2 * i + 2 < n) {
            nodes[i]->right = nodes[2 * i + 2];
        }
    }

    Node* root = nodes[0];
    Solution sol;
    vector<int> ans = sol.topView(root);
    for (int val : ans) {
        cout << val << " ";
    }
    cout << "\n";
    return 0;
}
